queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?genre WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasShows ?child ; p:hasTelevision_Channels ?parent . } GROUP BY ?child }
  ?child p:genre ?genre .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Television_Channels } }
  FILTER(?nf = ?total)
}

